// // This module implements an 8-bit synchronous reset register that loads data on the falling edge of the clock and resets to 11111111 when the reset signal is low.
module register8bit_sync_reset (
    input wire clk,
    input wire rst,
    input wire load,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);

    always @(posedge clk) begin
        if (rst)
            data_out <= 8'b00000000;
        else if (load)
            data_out <= data_in;
    end

endmodule
